11→export async function cleanupTestIndices(
12→	opensearchService: OpensearchService,
13→): Promise<void> {
14→	try {
15→		const client = opensearchService.getClient();
16→		const indices = await client.cat.indices({ format: 'json' });
17→		const testIndices = (indices.body as { index: string }[])
18→			.filter((idx) => idx.index.startsWith('e2e_test_'))
19→			.map((idx) => idx.index);
20→
21→		for (const indexName of testIndices) {
22→			await opensearchService.deleteIndex({ indexName });
23→		}
24→	} catch {
25→		// Ignore cleanup errors
26→	}
27→}
