 17→@Injectable()
 18→export class OpensearchNeuralService implements OnModuleInit {
 19→	private readonly logger = new Logger(OpensearchNeuralService.name);
 20→	private indexName: string;
 21→	private modelId: string | null = null;
 22→
 23→	constructor(
 24→		private readonly opensearchService: OpensearchService,
 25→		private readonly configService: EnvConfigService,
 26→	) {}
 27→
 28→	async onModuleInit(): Promise<void> {
 29→		this.indexName = this.configService.get<string>({ key: OPENSEARCH_INDEX_NAME });
 30→		await this.resolveModelId();
 31→	}
 32→
 33→	@Interval(MODEL_REFRESH_INTERVAL_MS)
 34→	async refreshModelId(): Promise<void> {
 35→		await this.resolveModelId();
 36→	}
 37→
 38→	private async resolveModelId(): Promise<void> {
 39→		try {
 40→			const modelId = await this.opensearchService.findDeployedModelId({
 41→				modelGroupName: MODEL_GROUP_NAME,
 42→			});
 43→
 44→			if (modelId && modelId !== this.modelId) {
 45→				const previousModelId = this.modelId;
 46→				this.modelId = modelId;
 47→				this.logger.log(`Model ID updated: ${previousModelId ?? 'none'} -> ${modelId}`);
 48→			} else if (!modelId) {
 49→				this.logger.warn(
 50→					'No deployed model found. Neural search will not work until bootstrap is run.',
 51→				);
 52→			}
 53→		} catch {
 54→			this.logger.warn('Failed to resolve model ID. OpenSearch may not be available.');
 55→		}
 56→	}
 57→
 58→	private getModelId(): string {
 59→		if (!this.modelId) {
 60→			throw new Error(
 61→				'Neural search model not available. Run: npm run cli:dev -- bootstrap-neural-search',
 62→			);
 63→		}
 64→		return this.modelId;
 65→	}
