 69→		[/\bt shirt(s)?\b/gi, 't-shirt$1'],
 70→		[/\bv[\s-]?neck\b/gi, 'v-neck'],
 71→		[/\bcrew[\s-]?neck\b/gi, 'crewneck'],
 72→		[/\blong[\s-]?sleeve(s)?\b/gi, 'long-sleeve$1'],
 73→		[/\bshort[\s-]?sleeve(s)?\b/gi, 'short-sleeve$1'],
 74→		[/\bpolo[\s-]?shirt(s)?\b/gi, 'polo t-shirt$1'],
 75→		[/\bsweat[\s-]?shirt(s)?\b/gi, 'sweatshirt$1'],
 76→		[/\bsweat[\s-]?pant(s)?\b/gi, 'sweatpant$1'],
 77→		[/\bzip[\s-]?up(s)?\b/gi, 'zip-up$1'],
 78→		[/\bhalf[\s-]?zip(s)?\b/gi, 'half-zip$1'],
 79→		[/\btote[\s-]?bag(s)?\b/gi, 'tote bag$1'],
 80→		[/\bdri[\s-]?fit\b/gi, 'dri-fit'],
 81→		[/\bslim[\s-]?fit\b/gi, 'slim fit'],
 82→		[/\btank[\s-]?top(s)?\b/gi, 'tank top$1'],
 83→	];
