 85→	private normalizeQuery({ text }: { text: string }): string {
 86→		let normalized = text.toLowerCase().trim();
 87→
 88→		for (const [pattern, replacement] of this.QUERY_SYNONYMS) {
 89→			normalized = normalized.replace(pattern, replacement);
 90→		}
 91→
 92→		return normalized;
 93→	}
