183→	@LogExecution({ logParams: false, logResponse: false })
184→	async bulkIndexProducts({
185→		indexName,
186→		styles,
187→	}: {
188→		indexName: string;
189→		styles: IStylesMvBase[];
190→	}): Promise<{ indexed: number; errors: number }> {
191→		if (styles.length === 0) {
192→			return { indexed: 0, errors: 0 };
193→		}
194→
195→		const documents = styles.map((style) =>
196→			this.transformStyleToOpensearchProduct({ style }),
197→		);
198→
199→		return this.opensearchService.bulkIndex({ indexName, documents });
200→	}
