202→	@LogExecution({
203→		paramFormatter: (params: [{ queryText: string; size: number }]) => ({
204→			queryText: params[0].queryText,
205→			size: params[0].size,
206→		}),
207→		responseFormatter: (response: IOpensearchProduct[]) => ({
208→			totalResults: response.length,
209→		}),
210→	})
211→	async searchProducts({
212→		queryText,
213→		size = 20,
214→	}: {
215→		queryText: string;
216→		size?: number;
217→	}): Promise<IOpensearchProduct[]> {
218→		const normalizedQuery = this.normalizeQuery({ text: queryText });
219→		const hits = await this.opensearchService.search({
220→			indexName: this.indexName,
221→			searchPipeline: 'hybrid-search-pipeline',
222→			body: {
223→				size,
224→				query: {
225→					hybrid: {
226→						queries: [
227→							{
228→								bool: {
229→									should: [
230→										{
231→											match_phrase: {
232→												combined_text_for_embedding: { query: normalizedQuery, boost: 1 },
233→											},
234→										},
235→										{ match_phrase: { name: { query: normalizedQuery, boost: 1 } } },
236→										{ match: { name: { query: normalizedQuery, boost: 1 } } },
237→										{ match_phrase: { features: { query: normalizedQuery, boost: 1 } } },
238→									],
239→									filter: [{ term: { status: 'active' } }],
240→								},
241→							},
242→							{
243→								neural: {
244→									product_embedding: {
245→										query_text: normalizedQuery,
246→										model_id: this.getModelId(),
247→										k: size,
248→										filter: { term: { status: 'active' } },
249→									},
250→								},
251→							},
252→						],
253→					},
254→				},
255→				_source: { excludes: ['product_embedding', 'combined_text_for_embedding'] },
256→			},
257→		});
258→
259→		return hits.slice(0, size).map((hit) => ({
260→			...(hit._source as IOpensearchProduct),
261→			_id: hit._id,
262→		}));
263→	}
