265→	private normalizeCondensedFeatures({
266→		condensedFeatures,
267→	}: {
268→		condensedFeatures: unknown;
269→	}): string[] | null {
270→		if (condensedFeatures === null || condensedFeatures === undefined) {
271→			return null;
272→		}
273→
274→		if (typeof condensedFeatures === 'string') {
275→			return [condensedFeatures];
276→		}
277→
278→		if (Array.isArray(condensedFeatures)) {
279→			return condensedFeatures.map(String);
280→		}
281→
282→		if (typeof condensedFeatures === 'object') {
283→			return Object.values(condensedFeatures).flatMap((value: unknown) =>
284→				Array.isArray(value) ? value.map(String) : [String(value)],
285→			);
286→		}
287→
288→		return [JSON.stringify(condensedFeatures)];
289→	}
290→
291→	private buildCombinedTextForEmbedding({ style }: { style: IStylesMvBase }): string {
292→		const normalizedCondensedFeatures = this.normalizeCondensedFeatures({
293→			condensedFeatures: style.condensed_features,
294→		});
295→
296→		const cleanText = ({ text }: { text: string | null | undefined }): string => {
297→			if (!text) return '';
298→			return text
299→				.replace(/\r\n|\r|\n/g, ' ')
300→				.replace(/[*#]+\s?/g, '')
301→				.replace(/<[^>]*>/g, '')
302→				.replace(/\s{2,}/g, ' ')
303→				.trim();
304→		};
305→
306→		const parts: string[] = [];
307→
308→		if (style.name) parts.push(style.name + '.');
309→
310→		const cats = [
311→			style.product_type,
312→			style.style_type,
313→			style.primary_category_name,
314→		].filter(Boolean);
315→		if (cats.length) parts.push(cats.join(', ') + '.');
316→
317→		const features = cleanText({ text: style.features });
318→		if (features) parts.push(features + '.');
319→
320→		const description = normalizedCondensedFeatures
321→			? cleanText({ text: normalizedCondensedFeatures.join(', ') })
322→			: '';
323→		if (description) parts.push(description);
324→
325→		if (style.decoration_method) parts.push(`Decoration: ${style.decoration_method}.`);
326→		if (style.manufacturer) parts.push(`Made by ${style.manufacturer}.`);
327→		if (style.brand?.length) parts.push(`Brand: ${style.brand.join(', ')}.`);
328→
329→		return parts.join(' ');
330→	}
331→
332→	private transformStyleToOpensearchProduct({
333→		style,
334→	}: {
335→		style: IStylesMvBase;
336→	}): IOpensearchProduct {
337→		return {
338→			_id: style._id,
339→			style_id: style.style_id,
340→			product_id: style.product_id,
341→			name: style.name ?? '',
342→			features: style.features,
343→			general_comments: style.general_comments,
344→			decoration_method: style.decoration_method,
345→			manufacturer: style.manufacturer,
346→			primary_category_id: style.primary_category_id,
347→			primary_category_name: style.primary_category_name,
348→			product_type: style.product_type,
349→			style_type: style.style_type,
350→			broad_category_names: style.broad_category_names,
351→			sub_category_names: style.sub_category_names,
352→			minimum_quantity: style.minimum_quantity,
353→			min_qty: style.min_qty,
354→			default_quote_qty: style.default_quote_qty,
355→			sizes: style.sizes,
356→			turn_time: style.turn_time,
357→			rush_turn_time: style.rush_turn_time,
358→			no_minimum: style.no_minimum ? 1 : 0,
359→			price_level: style.price_level,
360→			rating_score: style.rating_score !== null ? Number(style.rating_score) : null,
361→			rating_count: style.rating_count,
362→			default_unit_prices: style.default_unit_prices,
363→			colors: style.colors,
364→			style_card_image_url: style.style_card_image_url,
365→			link: style.link,
366→			brand: style.brand,
367→			condensed_features: this.normalizeCondensedFeatures({
368→				condensedFeatures: style.condensed_features,
369→			}),
370→			status: style.status,
371→			created_at:
372→				style.created_at instanceof Date
373→					? style.created_at.toISOString()
374→					: String(style.created_at),
375→			updated_at:
376→				style.updated_at instanceof Date
377→					? style.updated_at.toISOString()
378→					: String(style.updated_at),
379→			deleted_at: style.deleted_at
380→				? style.deleted_at instanceof Date
381→					? style.deleted_at.toISOString()
382→					: String(style.deleted_at)
383→				: null,
384→			combined_text_for_embedding: this.buildCombinedTextForEmbedding({ style }),
385→			// combined_text_for_embedding:  style.embedding_text ?? this.buildCombinedTextForEmbedding({ style }),
386→		};
387→	}
388→}
