 19→const INGEST_PIPELINE_ID = 'products-neural-pipeline';
 20→const SEARCH_PIPELINE_ID = 'hybrid-search-pipeline';
 21→
 22→interface BootstrapNeuralSearchOptions {
 23→	modelFormat?: string;
 24→	batchSize?: number;
 25→	concurrency?: number;
 26→}
 27→
 28→@Command({
 29→	name: 'bootstrap-neural-search',
 30→	description:
 31→		'Full neural search bootstrap: configure cluster, train model, create index, sync products',
 32→})
 33→export class BootstrapNeuralSearchCommand extends CommandRunner {
 34→	private readonly logger = new Logger(BootstrapNeuralSearchCommand.name);
 35→	private isShuttingDown = false;
 36→	private currentOperation: Promise<void> | null = null;
 37→	private isCancelled = false;
 38→
 39→	constructor(
 40→		private readonly opensearchService: OpensearchService,
 41→		private readonly opensearchNeuralService: OpensearchNeuralService,
 42→		private readonly stylesMvModel: StylesMvModel,
 43→		private readonly configService: EnvConfigService,
 44→	) {
 45→		super();
 46→		this.setupGracefulShutdown();
 47→	}
 48→
 49→	@CronJobExecution({ jobName: 'bootstrap-neural-search' })
 50→	async run(
 51→		_passedParams: string[],
 52→		options: BootstrapNeuralSearchOptions,
 53→	): Promise<void> {
 54→		if (this.isShuttingDown) {
 55→			this.logger.warn('Command cancelled due to shutdown signal');
 56→			return;
 57→		}
 58→
 59→		const modelFormat = options.modelFormat ?? 'TORCH_SCRIPT';
 60→		const batchSize = options.batchSize ?? 60;
 61→		const concurrency = options.concurrency ?? 2;
 62→		const startTime = Date.now();
 63→
 64→		try {
 65→			const indexName = this.configService.get<string>({ key: OPENSEARCH_INDEX_NAME });
 66→
 67→			this.logger.log('=== Step 1/9: Cleaning up existing resources ===');
 68→			await this.cleanupExistingResources({ indexName });
 69→
 70→			this.logger.log('=== Step 2/9: Configuring cluster ML settings ===');
 71→			await this.opensearchService.configureClusterMLSettings();
 72→
 73→			this.logger.log('=== Step 3/9: Registering model group ===');
 74→			const modelGroupId = await this.opensearchService.registerModelGroup({
 75→				name: MODEL_GROUP_NAME,
 76→				description: 'Model group for neural search embeddings',
 77→			});
 78→
 79→			this.logger.log(
 80→				'=== Step 4/9: Registering model (this may take several minutes) ===',
 81→			);
 82→			const registerTaskId = await this.opensearchService.registerModel({
 83→				name: MODEL_NAME,
 84→				version: MODEL_VERSION,
 85→				modelGroupId,
 86→				modelFormat,
 87→			});
 88→
 89→			this.logger.log('Waiting for model registration to complete...');
 90→			const registerResult = await this.opensearchService.waitForTask({
 91→				taskId: registerTaskId,
 92→				intervalMs: 10000,
 93→				maxAttempts: 120,
 94→			});
 95→			const modelId = registerResult.model_id;
 96→
 97→			if (!modelId) {
 98→				throw new Error('Model registration completed but no model_id returned');
 99→			}
100→
101→			this.logger.log(`Model registered: ${modelId}`);
102→
103→			this.logger.log(
104→				'=== Step 5/9: Deploying model (this may take several minutes) ===',
105→			);
106→			const deployTaskId = await this.opensearchService.deployModel({ modelId });
107→
108→			this.logger.log('Waiting for model deployment to complete...');
109→			await this.opensearchService.waitForTask({
110→				taskId: deployTaskId,
111→				intervalMs: 10000,
112→				maxAttempts: 120,
113→			});
114→			this.logger.log('Model deployed successfully');
115→
116→			this.logger.log('=== Step 6/9: Creating ingest pipeline ===');
117→			await this.opensearchService.createIngestPipeline({
118→				pipelineId: INGEST_PIPELINE_ID,
119→				modelId,
120→				sourceField: 'combined_text_for_embedding',
121→				targetField: 'product_embedding',
122→			});
123→
124→			this.logger.log('=== Step 7/9: Creating search pipeline ===');
125→			await this.opensearchService.createSearchPipeline({
126→				pipelineId: SEARCH_PIPELINE_ID,
127→				normalizationTechnique: 'min_max',
128→				combinationTechnique: 'arithmetic_mean',
129→				weights: [0.2, 0.8],
130→			});
131→
132→			this.logger.log(`=== Step 8/9: Creating index ${indexName} ===`);
133→			await this.opensearchNeuralService.createProductsIndex({ indexName });
134→
135→			if (this.isCancelled) {
136→				this.logger.warn('Bootstrap cancelled before product sync');
137→				return;
138→			}
139→
140→			this.logger.log(
141→				'=== Step 9/9: Syncing products (embedding generation on ingest) ===',
142→			);
143→			this.logger.log(`Batch size: ${batchSize}, Concurrency: ${concurrency}`);
144→
145→			const totalCount = await this.stylesMvModel.count();
146→			this.logger.log(`Total products to index: ${totalCount}`);
147→
148→			if (totalCount === 0) {
149→				this.logger.warn('No products found to index');
150→				return;
151→			}
152→
153→			const totalBatches = Math.ceil(totalCount / batchSize);
154→			const batches = Array.from({ length: totalBatches }, (_, i) => ({
155→				offset: i * batchSize,
156→				limit: batchSize,
157→			}));
158→
159→			const progressBar = new ProgressBar({ total: totalCount });
160→			let totalIndexed = 0;
161→			let totalErrors = 0;
162→
163→			this.currentOperation = this.processBatches({
164→				batches,
165→				concurrency,
166→				indexName,
167→				progressBar,
168→				onBatchComplete: (indexed, errors) => {
169→					totalIndexed += indexed;
170→					totalErrors += errors;
171→				},
172→			});
173→
174→			await this.currentOperation;
175→
176→			if (!this.isCancelled) {
177→				progressBar.finish();
178→			}
179→
180→			const duration = ((Date.now() - startTime) / 1000).toFixed(1);
181→
182→			this.logger.log('=== Bootstrap complete ===');
183→			this.logger.log(`Duration: ${duration}s`);
184→			this.logger.log(`Products indexed: ${totalIndexed}, Errors: ${totalErrors}`);
185→			this.logger.log(`Model ID: ${modelId} (resolved dynamically at app startup)`);
186→		} catch (error) {
187→			// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
188→			if (this.isShuttingDown || this.isCancelled) {
189→				this.logger.warn('Command interrupted during shutdown');
190→				return;
191→			}
192→			this.logger.error(`Bootstrap failed: ${(error as Error).message}`);
193→			process.exit(1);
194→		} finally {
195→			this.currentOperation = null;
196→		}
197→	}
