199→	private async cleanupExistingResources({
200→		indexName,
201→	}: {
202→		indexName: string;
203→	}): Promise<void> {
204→		this.logger.log('Deleting index...');
205→		await this.opensearchService.deleteIndex({ indexName });
206→
207→		this.logger.log('Deleting pipelines...');
208→		await this.opensearchService.deleteSearchPipeline({ pipelineId: SEARCH_PIPELINE_ID });
209→		await this.opensearchService.deleteIngestPipeline({ pipelineId: INGEST_PIPELINE_ID });
210→
211→		this.logger.log('Looking for existing model group...');
212→		const modelGroupId = await this.opensearchService.searchModelGroupByName({
213→			name: MODEL_GROUP_NAME,
214→		});
215→
216→		if (modelGroupId) {
217→			this.logger.log(`Found model group: ${modelGroupId}, cleaning up models...`);
218→			const models = await this.opensearchService.searchModelsByGroup({ modelGroupId });
219→
220→			for (const model of models) {
221→				if (model.model_state === 'DEPLOYED' || model.model_state === 'DEPLOYING') {
222→					this.logger.log(`Undeploying model: ${model.model_id}`);
223→					await this.opensearchService.undeployModel({ modelId: model.model_id });
224→					await new Promise((resolve) => setTimeout(resolve, 3000));
225→				}
226→
227→				this.logger.log(`Deleting model: ${model.model_id}`);
228→				await this.opensearchService.deleteModel({ modelId: model.model_id });
229→			}
230→
231→			this.logger.log('Deleting model group...');
232→			await this.opensearchService.deleteModelGroup({ modelGroupId });
233→			this.logger.log('Waiting for ML index refresh...');
234→			await new Promise((resolve) => setTimeout(resolve, 10000));
235→		} else {
236→			this.logger.log('No existing model group found');
237→		}
238→
239→		this.logger.log('Cleanup complete');
240→	}
