242→	private async processBatches({
243→		batches,
244→		concurrency,
245→		indexName,
246→		progressBar,
247→		onBatchComplete,
248→	}: {
249→		batches: { offset: number; limit: number }[];
250→		concurrency: number;
251→		indexName: string;
252→		progressBar: ProgressBar;
253→		onBatchComplete: (indexed: number, errors: number) => void;
254→	}): Promise<void> {
255→		await runWithConcurrencyLimit({
256→			items: batches,
257→			concurrency,
258→			handler: async (batch) => {
259→				if (this.isCancelled) {
260→					return { indexed: 0, errors: 0 };
261→				}
262→
263→				const styles = await this.stylesMvModel.findAll({
264→					limit: batch.limit,
265→					offset: batch.offset,
266→				});
267→
268→				if (styles.length === 0) {
269→					return { indexed: 0, errors: 0 };
270→				}
271→
272→				return this.opensearchNeuralService.bulkIndexProducts({
273→					indexName,
274→					styles,
275→				});
276→			},
277→			onItemComplete: (result) => {
278→				progressBar.increment(result.indexed + result.errors);
279→				onBatchComplete(result.indexed, result.errors);
280→			},
281→			onItemError: (error) => {
282→				this.logger.error(`Batch processing error: ${(error as Error).message}`);
283→			},
284→		});
285→	}
286→
287→	@Option({
288→		flags: '-f, --model-format <modelFormat>',
289→		description: 'Model format: TORCH_SCRIPT or ONNX (default: TORCH_SCRIPT)',
290→	})
291→	parseModelFormat(value: string): string {
292→		const valid = ['TORCH_SCRIPT', 'ONNX'];
293→		if (!valid.includes(value)) {
294→			throw new Error(`Model format must be one of: ${valid.join(', ')}`);
295→		}
296→		return value;
297→	}
298→
299→	@Option({
300→		flags: '-b, --batch-size <batchSize>',
301→		description: 'Products per batch (default: 150)',
302→	})
303→	parseBatchSize(value: string): number {
304→		const size = parseInt(value, 10);
305→		if (isNaN(size) || size < 1 || size > 1000) {
306→			throw new Error('Batch size must be between 1 and 1000');
307→		}
308→		return size;
309→	}
310→
311→	@Option({
312→		flags: '-c, --concurrency <concurrency>',
313→		description: 'Concurrent batch operations (default: 5)',
314→	})
315→	parseConcurrency(value: string): number {
316→		const conc = parseInt(value, 10);
317→		if (isNaN(conc) || conc < 1 || conc > 20) {
318→			throw new Error('Concurrency must be between 1 and 20');
319→		}
320→		return conc;
321→	}
322→
323→	private setupGracefulShutdown(): void {
324→		const signals: NodeJS.Signals[] = ['SIGTERM', 'SIGINT', 'SIGHUP', 'SIGQUIT'];
325→
326→		signals.forEach((signal) => {
327→			process.on(signal, () => {
328→				void this.handleShutdown(signal);
329→			});
330→		});
331→
332→		process.on('uncaughtException', (error) => {
333→			this.logger.error(`Uncaught exception: ${error.message}`);
334→			void this.handleShutdown('SIGTERM');
335→		});
336→
337→		process.on('unhandledRejection', (reason) => {
338→			this.logger.error(`Unhandled rejection: ${String(reason)}`);
339→			void this.handleShutdown('SIGTERM');
340→		});
341→	}
342→
343→	private async handleShutdown(signal: string): Promise<void> {
344→		if (this.isShuttingDown) {
345→			this.logger.warn('Force shutdown requested, exiting immediately');
346→			process.exit(1);
347→		}
348→
349→		this.logger.warn(`Received ${signal} signal, initiating graceful shutdown...`);
350→		this.isShuttingDown = true;
351→		this.isCancelled = true;
352→
353→		try {
354→			if (this.currentOperation) {
355→				this.logger.log('Waiting for current operation to complete...');
356→
357→				const shutdownTimeout = setTimeout(() => {
358→					this.logger.error('Graceful shutdown timeout, forcing exit');
359→					process.exit(1);
360→				}, 30000);
361→
362→				await this.currentOperation;
363→				clearTimeout(shutdownTimeout);
364→			}
365→
366→			this.logger.log('Graceful shutdown completed');
367→			process.exit(0);
368→		} catch (error) {
369→			this.logger.error(`Error during shutdown: ${(error as Error).message}`);
370→			process.exit(1);
371→		}
372→	}
373→}
